code_string = """from qiskit import transpile
from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    def compute_expectation(counts, graph):
        total_shots = sum(counts.values())
        expectation = 0.0
        for bitstring, count in counts.items():
            reversed_bitstring = bitstring[::-1]
            cut_value = 0
            for u, v in graph.edges():
                if reversed_bitstring[u] != reversed_bitstring[v]:
                    cut_value += 1
            expectation += (count / total_shots) * cut_value
        return -expectation

    initial_params = [0.1] * circuit.num_parameters

    def objective(params):
        parameter_binds = [{circuit.parameters[i]: [params[i]] for i in range(len(params))}]
        t_circuit = transpile(circuit, aer_sim)
        job = aer_sim.run(t_circuit, parameter_binds=parameter_binds, shots=8192)
        counts = job.result().get_counts()
        return compute_expectation(counts, graph)

    result = minimize(objective, initial_params, method='COBYLA')

    optimal_params = result.x
    parameter_binds = [{circuit.parameters[i]: [optimal_params[i]] for i in range(len(optimal_params))}]
    t_circuit = transpile(circuit, aer_sim)
    job = aer_sim.run(t_circuit, parameter_binds=parameter_binds, shots=8192)
    counts = job.result().get_counts()

    sorted_counts = sorted(counts.items(), key=lambda x: x[1], reverse=True)
    top_two = []
    for i in range(min(2, len(sorted_counts))):
        bitstring = sorted_counts[i][0]
        reversed_bitstring = bitstring[::-1]
        top_two.append(reversed_bitstring)

    return top_two
"""
